const express = require('express');
const app = express();
const mongoose = require('mongoose');

// Connect to MongoDB
mongoose.connect('mongodb://localhost/mydatabase', { useNewUrlParser: true, useUnifiedTopology: true });

// Define a schema for the data model
const DataModel = new mongoose.Schema({
  name: String,
  age: Number,
  email: String
});

// Create a Mongoose model from the schema
const Data = mongoose.model('Data', DataModel);

// Middleware to parse JSON bodies
app.use(express.json());

// API endpoint to query data
app.post('/query', async (req, res) => {
  try {
    const filters = req.body;
    const result = await Data.find(filters).exec();
    res.json(result);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error querying data' });
  }
});

// API endpoint to query data with pagination
app.post('/query/paginate', async (req, res) => {
  try {
    const filters = req.body;
    const page = req.body.page || 1;
    const limit = req.body.limit || 10;
    const skip = (page - 1) * limit;
    const result = await Data.find(filters).skip(skip).limit(limit).exec();
    res.json(result);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error querying data' });
  }
});

// Start the server
const port = 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});